    next_node = None

    for node in unvisited_nodes:
        total_distance_to_trucks = np.sum([distance_matrix[node][truck_node] for truck_node in truck_nodes])
        is_reachable = any([distance_matrix[node][truck_node] < np.inf for truck_node in truck_nodes])
